const PROOF_DIM = 1024;
const PROOF_TRIALS = 100;
const SIMILARITY_EPSILON = 0.05;
const PHI = (1.0 + Math.sqrt(5.0)) / 2.0;
const PHI_SQ = PHI * PHI;
const LOG2_3 = Math.log2(3);

// ═══════════════════════════════════════════════════════════════════════════════
// SEEDED RNG (simple LCG for reproducibility)
// ═══════════════════════════════════════════════════════════════════════════════

class SeededRNG {
  private state: number;

  constructor(seed: number) {
    this.state = seed & 0x7fffffff;
  }

  next(): number {
    this.state = (this.state * 1103515245 + 12345) & 0x7fffffff;
    return this.state;
  }

  trit(): number {
    return (this.next() % 3) - 1; // -1, 0, +1
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// VSA OPERATIONS
// ═══════════════════════════════════════════════════════════════════════════════

function randomVector(dim: number, seed: number): TernaryVector {
  const rng = new SeededRNG(seed);
  const data: number[] = [];
  for (let i = 0; i < dim; i++) {
    data.push(rng.trit());
  }
  return { dimension: dim, data };
}

function bind(a: TernaryVector, b: TernaryVector): TernaryVector {
  const data = a.data.map((v, i) => v * b.data[i]);
  return { dimension: a.dimension, data };
}

function unbind(bound: TernaryVector, key: TernaryVector): TernaryVector {
  return bind(bound, key);
}

function bundle3(a: TernaryVector, b: TernaryVector, c: TernaryVector): TernaryVector {
  const data: number[] = [];
  for (let i = 0; i < a.dimension; i++) {
    const s = a.data[i] + b.data[i] + c.data[i];
    data.push(s > 0 ? 1 : s < 0 ? -1 : 0);
  }
  return { dimension: a.dimension, data };
}

function cosineSimilarity(a: TernaryVector, b: TernaryVector): number {
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.dimension; i++) {
    dot += a.data[i] * b.data[i];
    normA += a.data[i] * a.data[i];
    normB += b.data[i] * b.data[i];
  }
  if (normA === 0 || normB === 0) return 0;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

function permute(v: TernaryVector, k: number): TernaryVector {
  const d = v.dimension;
  const shift = ((k % d) + d) % d;
  const data = [...v.data.slice(shift), ...v.data.slice(0, shift)];
  return { dimension: d, data };
}

