function proveBindInverse(): ProofResult {
  const a = randomVector(PROOF_DIM, 42);
  const b = randomVector(PROOF_DIM, 137);
  const bound = bind(a, b);
  const recovered = unbind(bound, a);
  const sim = cosineSimilarity(recovered, b);
  return { name: "bind_inverse", passed: sim > 0.60, expected: 0.60, actual: sim, epsilon: SIMILARITY_EPSILON };
}

function proveBindCommutative(): ProofResult {
  const a = randomVector(PROOF_DIM, 123);
  const b = randomVector(PROOF_DIM, 456);
  const ab = bind(a, b);
  const ba = bind(b, a);
  const match = ab.data.every((v, i) => v === ba.data[i]);
  return { name: "bind_commutative", passed: match, expected: 1.0, actual: match ? 1.0 : 0.0, epsilon: 0 };
}

function proveBindSelfIdentity(): ProofResult {
  const a = randomVector(PROOF_DIM, 777);
  const selfBind = bind(a, a);
  const ok = selfBind.data.every((v, i) => v === (a.data[i] === 0 ? 0 : 1));
  return { name: "bind_self_identity", passed: ok, expected: 1.0, actual: ok ? 1.0 : 0.0, epsilon: 0 };
}

function proveBindAssociative(): ProofResult {
  const a = randomVector(PROOF_DIM, 2024);
  const b = randomVector(PROOF_DIM, 2025);
  const c = randomVector(PROOF_DIM, 2026);
  const abC = bind(bind(a, b), c);
  const aBc = bind(a, bind(b, c));
  const match = abC.data.every((v, i) => v === aBc.data[i]);
  return { name: "bind_associative", passed: match, expected: 1.0, actual: match ? 1.0 : 0.0, epsilon: 0 };
}

function proveBundleConvergence(): ProofResult {
  const a = randomVector(PROOF_DIM, 1001);
  const b = randomVector(PROOF_DIM, 1002);
  const c = randomVector(PROOF_DIM, 1003);
  const bundled = bundle3(a, b, c);
  const simA = cosineSimilarity(bundled, a);
  const simB = cosineSimilarity(bundled, b);
  const simC = cosineSimilarity(bundled, c);
  const ok = simA > 0.15 && simB > 0.15 && simC > 0.15;
  return { name: "bundle_convergence", passed: ok, expected: 0.15, actual: Math.min(simA, simB, simC), epsilon: 0.05 };
}

function proveOrthogonality(): ProofResult {
  let total = 0;
  const trials = 50;
  for (let t = 0; t < trials; t++) {
    const a = randomVector(PROOF_DIM, 10000 + t * 2);
    const b = randomVector(PROOF_DIM, 10001 + t * 2);
    total += Math.abs(cosineSimilarity(a, b));
  }
  const avg = total / trials;
  return { name: "orthogonality", passed: avg < 0.15, expected: 0.15, actual: avg, epsilon: 0.05 };
}

function provePermuteCycle(): ProofResult {
  const dim = 256;
  const a = randomVector(dim, 55);
  const k = 17;
  const p1 = permute(a, k);
  const p2 = permute(p1, dim - k);
  const sim = cosineSimilarity(p2, a);
  return { name: "permute_cycle", passed: Math.abs(sim - 1.0) < 0.001, expected: 1.0, actual: sim, epsilon: 0.001 };
}

function proveSimilarityBounds(): ProofResult {
  let ok = true;
  for (let t = 0; t < PROOF_TRIALS; t++) {
    const a = randomVector(512, 20000 + t * 2);
    const b = randomVector(512, 20001 + t * 2);
    const sim = cosineSimilarity(a, b);
    if (sim < -1.001 || sim > 1.001) { ok = false; break; }
  }
  return { name: "similarity_bounds", passed: ok, expected: 1.0, actual: ok ? 1.0 : 0.0, epsilon: 0.001 };
}

function proveTrinityIdentity(): ProofResult {
  const trinity = PHI_SQ + 1.0 / PHI_SQ;
  const ok = Math.abs(trinity - 3.0) < 1e-12;
  return { name: "trinity_identity", passed: ok, expected: 3.0, actual: trinity, epsilon: 1e-12 };
}

function proveInformationDensity(): ProofResult {
  const compression = 32.0 / LOG2_3;
  const ok = Math.abs(LOG2_3 - 1.58496) < 0.001 && compression > 20.0;
  return { name: "information_density", passed: ok, expected: 1.58496, actual: LOG2_3, epsilon: 0.001 };
}

